import { Component, EventEmitter, Output } from '@angular/core';
import { TaskService } from '../../services/task.service';
import { Task } from '../../models/task.model';

@Component({
  selector: 'app-task-form',
  templateUrl: './task-form.component.html',
  styleUrls: ['./task-form.component.css'],
})
export class TaskFormComponent {
  title = '';
  description = '';
  priority: 'low' | 'medium' | 'high' = 'medium';
  isSubmitting = false;
  successMessage = '';

  @Output() taskCreated = new EventEmitter<Task>();

  constructor(private taskService: TaskService) {}

  onSubmit(): void {
    if (!this.title.trim()) return;

    this.isSubmitting = true;
    this.taskService
      .createTask({
        title: this.title.trim(),
        description: this.description.trim(),
        priority: this.priority,
      })
      .subscribe({
        next: (task) => {
          this.taskCreated.emit(task);
          this.successMessage = `"${task.title}" created!`;
          this.resetForm();
          this.isSubmitting = false;
          setTimeout(() => (this.successMessage = ''), 3000);
        },
        error: (err) => {
          console.error('Failed to create task', err);
          this.isSubmitting = false;
        },
      });
  }

  resetForm(): void {
    this.title = '';
    this.description = '';
    this.priority = 'medium';
  }
}
<div class="form-card">
  <h2><i class="fas fa-plus-circle"></i> Add New Task</h2>

  <div *ngIf="successMessage" class="success-banner">
    <i class="fas fa-check"></i> {{ successMessage }}
  </div>

  <form (ngSubmit)="onSubmit()">
    <div class="form-group">
      <label for="title">Title *</label>
      <input
        id="title"
        type="text"
        [(ngModel)]="title"
        name="title"
        placeholder="What needs to be done?"
        required
      />
    </div>

    <div class="form-group">
      <label for="description">Description</label>
      <textarea
        id="description"
        [(ngModel)]="description"
        name="description"
        placeholder="Add details (optional)"
        rows="3"
      ></textarea>
    </div>

    <div class="form-group">
      <label for="priority">Priority</label>
      <select id="priority" [(ngModel)]="priority" name="priority">
        <option value="low">Low</option>
        <option value="medium">Medium</option>
        <option value="high">High</option>
      </select>
    </div>

    <button type="submit" class="btn btn-primary" [disabled]="isSubmitting || !title.trim()">
      <i class="fas" [ngClass]="isSubmitting ? 'fa-spinner fa-spin' : 'fa-plus'"></i>
      {{ isSubmitting ? 'Creating...' : 'Add Task' }}
    </button>
  </form>
</div>
